    };

    for (size_t i = 0; i < len && tx_idx < 62; i++) {
        tx_buf[tx_idx++] = m_lut[erp1_data[i] >> 4];
        tx_buf[tx_idx++] = m_lut[erp1_data[i] & 0x0F];
    }
    tx_buf[tx_idx++] = 0x00; // Post-amble

    cc1101_write_reg(0x06, tx_idx); // PKTLEN
    cc1101_strobe(0x3B); // SFTX
    cc1101_write_burst(0x3F, tx_buf, tx_idx); // FIFO Write
    cc1101_strobe(0x35); // STX

    // Wait for completion (GDO2 goes low)
    // For now simple delay or check
    vTaskDelay(pdMS_TO_TICKS(10));

