    cc1101_strobe(0x36); // SIDLE
    cc1101_write_reg(0x02, 0x0D); // GDO2: Async Serial Out
    cc1101_write_reg(0x08, 0x02); // PKTCTRL0: Async
    cc1101_strobe(0x34); // SRX

